const invoiceNumber = $('HTTP Request').first().json.data.invoice_number;
const rows = $input.all();

// Debug: log what we're working with
const allInvoiceNumbers = rows.map(row => row.json["Invoice Number"]).filter(Boolean);

const match = rows.filter(row => {
  const cellValue = row.json["Invoice Number"];
  if (!cellValue) return false;
  return String(cellValue).trim() === String(invoiceNumber).trim();
});

return [{
  json: {
    duplicate: match.length > 0 ? "true" : "false",
    invoice_number: invoiceNumber,
    found_in_sheet: allInvoiceNumbers,
    rows_checked: rows.length
  }
}];
